public double getPct(Object v) {
    if (v == null) {
        throw new IllegalArgumentException("Value cannot be null");
    }
    long count = getCount(v);
    long total = getSumFreq();
    return total == 0 ? Double.NaN : (double) count / total;
}

public double getPct(Object v) {
    if (v == null) {
        throw new IllegalArgumentException("Input value cannot be null");
    }
    if (!(v instanceof Comparable)) {
        throw new IllegalArgumentException("Input value must be Comparable");
    }
    long count = getCount(v);
    long total = getSumFreq();
    if (total == 0) {
        return Double.NaN;
    }
    return (double) count / total;
}

public double getPct(Object v) {
    return getPct((Comparable<?>) v);
}

